import time, threading

class TokenBucket:
    """Thread-safe token bucket rate limiter."""
    def __init__(self, rate: float, capacity: float):
        """
        rate: tokens added per second
        capacity: max tokens (burst allowance)
        """
        self.rate = rate
        self.capacity = capacity
        self.tokens = capacity
        self.last_refill = time.monotonic()
        self._lock = threading.Lock()

    def acquire(self, n=1) -> float:
        """Block until n tokens are available. Returns wait time."""
        with self._lock:
            now = time.monotonic()
            elapsed = now - self.last_refill
            self.tokens = min(self.capacity, self.tokens + elapsed * self.rate)
            self.last_refill = now

            if self.tokens >= n:
                self.tokens -= n
                return 0.0
            else:
                wait = (n - self.tokens) / self.rate
                self.tokens = 0
                return wait

    def __call__(self, func):
        """Use as decorator"""
        def wrapper(*args, **kwargs):
            wait = self.acquire()
            if wait > 0: time.sleep(wait)
            return func(*args, **kwargs)
        return wrapper

# 10 requests/second, burst of 20
limiter = TokenBucket(rate=10, capacity=20)

@limiter
def call_api(endpoint):
    return requests.get(endpoint)

import time
import requests
import jwt  # PyJWT library

# JWT verification
def verify_jwt(token: str, public_key: str, audience: str) -> dict:
    try:
        payload = jwt.decode(
            token,
            public_key,
            algorithms=['RS256'],  # always specify algorithm explicitly
            audience=audience,
            options={'require': ['exp', 'sub', 'aud']}
        )
        return payload
    except jwt.ExpiredSignatureError:
        raise ValueError('Token expired')
    except jwt.InvalidTokenError as e:
        raise ValueError(f'Invalid token: {e}')

# OAuth2 Client Credentials with token caching
class OAuth2Client:
    def __init__(self, token_url, client_id, client_secret):
        self.token_url = token_url
        self.creds = (client_id, client_secret)
        self._token = None
        self._expiry = 0

    def get_token(self) -> str:
        # Refresh 60s before expiry to avoid clock skew
        if time.time() < self._expiry - 60 and self._token:
            return self._token
        resp = requests.post(self.token_url,
            data={'grant_type': 'client_credentials'},
            auth=self.creds, timeout=10)
        resp.raise_for_status()
        data = resp.json()
        self._token = data['access_token']
        self._expiry = time.time() + data.get('expires_in', 3600)
        return self._token

    def get_headers(self) -> dict:
        return {'Authorization': f'Bearer {self.get_token()}'}

import time
from enum import Enum

class State(Enum):
    CLOSED    = 'closed'     # normal operation
    OPEN      = 'open'       # failing fast
    HALF_OPEN = 'half_open'  # testing recovery

class CircuitBreaker:
    def __init__(self, failure_threshold=5, recovery_timeout=30):
        self.threshold = failure_threshold
        self.timeout = recovery_timeout
        self.failures = 0
        self.state = State.CLOSED
        self.opened_at = None

    def call(self, func, *args, **kwargs):
        if self.state == State.OPEN:
            if time.time() - self.opened_at >= self.timeout:
                self.state = State.HALF_OPEN  # try recovery
            else:
                raise ConnectionError('Circuit OPEN — service unavailable')
        try:
            result = func(*args, **kwargs)
            self._on_success()
            return result
        except Exception as e:
            self._on_failure()
            raise

    def _on_success(self):
        self.failures = 0
        self.state = State.CLOSED  # reset on success

    def _on_failure(self):
        self.failures += 1
        if self.failures >= self.threshold or self.state == State.HALF_OPEN:
            self.state = State.OPEN
            self.opened_at = time.time()

cb = CircuitBreaker(failure_threshold=3, recovery_timeout=10)
result = cb.call(requests.get, 'https://api.example.com/data')
